public class NotificationService {
    public void notify(String type, String userId, String message) {
        if (type.equals("EMAIL")) {
            String email = userRepo.getEmail(userId);
            if (email != null && email.contains("@")) {
                smtpClient.send(email, "Notification", message);
                auditLog.record(userId, "email sent");
            }
        } else if (type.equals("SMS")) {
            String phone = userRepo.getPhone(userId);
            if (phone != null && phone.length() >= 10) {
                smsGateway.send(phone, message);
                auditLog.record(userId, "sms sent");
            }
        } else if (type.equals("PUSH")) {
            String token = userRepo.getDeviceToken(userId);
            if (token != null && !token.isEmpty()) {
                pushService.send(token, message);
                auditLog.record(userId, "push sent");
            }
        }
    }
}
